<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bot Explorer</title>
<style>
  body{margin:0;font-family:sans-serif;background:#222;color:#eee;}
  #controls{padding:10px;display:flex;gap:20px;align-items:center;}
  #maze{position:relative;width:400px;height:400px;margin:auto;border:2px solid #555;}
  canvas{background:#111;}
  button{padding:5px 10px;font-size:1rem;}
</style>
</head>
<body>
<div id="controls">
  <div>Completed: <span id="completed">0/24</span></div>
  <div>Timer: <span id="timer">0</span></div>
  <button id="reset">Reset</button>
</div>
<div id="maze"><canvas id="c" width="400" height="400"></canvas></div>

<script>
(() => {
const canvas=document.getElementById('c'),ctx=canvas.getContext('2d');
const rows=15,cols=15; // at least 15x15
const cellSize=canvas.width/cols;
let seed=Math.random()*1e9|0;

function rng(seed){ // simple mulberry32
  let t = seed += 0x6D2B79F5;
  t = Math.imul(t ^ t >>> 15, t | 1);
  t ^= t + Math.imul(t ^ t>>>7, t | 61);
  return ((t ^ t>>>14) >>> 0)/4294967296;
}

function generateMaze(seed){
  const walls=Array.from({length:rows},()=>Array(cols).fill(null));
  for(let r=0;r<rows;r++)for(let c=0;c<cols;c++){
    walls[r][c]={n:true,e:true,s:true,w:true};
  }
  const visited=Array.from({length:rows},()=>Array(cols).fill(false));
  function carve(r,c){
    visited[r][c]=true;
    const dirs=[{dr:-1,dc:0,n:'n',op:'s'}, {dr:0,dc:1,n:'e',op:'w'},
                {dr:1,dc:0,n:'s',op:'n'}, {dr:0,dc:-1,n:'w',op:'e'}];
    const order=dirs.sort(()=>rng(seed)-0.5);
    for(const d of order){
      const nr=r+d.dr,nc=c+d.dc;
      if(nr<0||nr>=rows||nc<0||nc>=cols||visited[nr][nc])continue;
      walls[r][c][d.n]=false;walls[nr][nc][d.op]=false;
      carve(nr,nc);
    }
  }
  carve(0,0); // perfect maze
  return {walls};
}

function initGame(seedArg){
  seed=seedArg!==undefined?seedArg:Math.random()*1e9|0;
  const {walls}=generateMaze(seed);
  game.wallsData=walls;
  game.size={rows,cols};
  game.spawn={r:0,c:0};
  // choose exit farthest from spawn
  let maxd=-1,exit={r:0,c:0};
  for(let r=0;r<rows;r++)for(let c=0;c<cols;c++){
    const d=Math.abs(r-0)+Math.abs(c-0);
    if(d>maxd){maxd=d;exit={r,c};}
  }
  game.exit=exit;
  // init bots
  game.bots=[];
  for(let i=0;i<24;i++){
    const bot={
      pos:{...game.spawn},
      dirOrder:shuffle(['n','e','s','w']),
      stack:[{pos:{...game.spawn},dirIndex:0}],
      visited:new Set([cellKey(game.spawn)]),
      deadEnds:new Set(),
      path:[{...game.spawn}],
      finishTick:null
    };
    game.bots.push(bot);
  }
  game.elapsed=0;
  render();
}

function cellKey({r,c}){return r+'_'+c;}
function shuffle(arr){for(let i=arr.length-1;i>0;--i){const j=Math.floor(rng(seed)* (i+1));[arr[i],arr[j]]=[arr[j],arr[i]];}return arr;}

window.game={};
Object.defineProperty(window.game,'elapsed',{get(){return game.elapsed}});
Object.defineProperty(window.game,'size',{get(){return game.size}});
Object.defineProperty(window.game,'spawn',{get(){return game.spawn}});
Object.defineProperty(window.game,'exit',{get(){return game.exit}});
Object.defineProperty(window.game,'walls',(r,c)=>game.wallsData[r][c]);

window.game.tick=function(n){
  for(let t=0;t<n;t++){
    if(game.elapsed===null)break;
    stepBots();
    game.elapsed++;
    render();
    if(allFinished()){game.elapsed=null;break;}
  }
};
window.game.reset=function(seedArg){initGame(seedArg);};

function allFinished(){return game.bots.every(b=>b.finishTick!==null);}
function stepBots(){
  for(const bot of game.bots){
    if(bot.finishTick!==null)continue;
    const {pos,stack}=bot;
    let moved=false;
    while(stack.length){
      const frame=stack[stack.length-1];
      if(frame.dirIndex>=4){ // all dirs tried
        stack.pop();
        bot.deadEnds.add(cellKey(pos));
        continue;
      }
      const dir=bot.dirOrder[frame.dirIndex++];
      const drc={n:{dr:-1,dc:0},e:{dr:0,dc:1},s:{dr:1,dc:0},w:{dr:0,dc:-1}}[dir];
      if(game.wallsData[pos.r][pos.c][dir])continue; // wall
      const nr=pos.r+drc.dr,nc=pos.c+drc.dc;
      const key=cellKey({r:nr,c:nc});
      if(bot.visited.has(key))continue;
      // move
      pos.r=nr;pos.c=nc;
      bot.visited.add(key);
      bot.path.push({r:pos.r,c:pos.c});
      stack.push({pos:{...pos},dirIndex:0});
      moved=true;
      break;
    }
    if(!moved && !bot.finishTick){ // dead end
      bot.deadEnds.add(cellKey(pos));
    }
    if(bot.pos.r===game.exit.r&&bot.pos.c===game.exit.c){
      bot.finishTick=game.elapsed+1; // tick when arrived
    }
  }
}

function render(){
  ctx.clearRect(0,0,canvas.width,canvas.height);
  drawMaze();
  drawBots();
  document.getElementById('completed').textContent=`${game.bots.filter(b=>b.finishTick!==null).length}/24`;
  document.getElementById('timer').textContent=game.elapsed===null?game.elapsed:game.elapsed;
}

function drawMaze(){
  ctx.strokeStyle='#888';
  for(let r=0;r<rows;r++)for(let c=0;c<cols;c++){
    const w=game.wallsData[r][c];
    const x=c*cellSize,y=r*cellSize;
    if(w.n)ctx.strokeRect(x,y,cellSize,1);
    if(w.s)ctx.strokeRect(x,y+cellSize-1,cellSize,1);
    if(w.w)ctx.strokeRect(x,y,1,cellSize);
    if(w.e)ctx.strokeRect(x+cellSize-1,y,1,cellSize);
  }
}

function drawBots(){
  const colors=['#f00','#0f0','#00f','#ff0','#f0f','#0ff','#c00','#0c0','#00c','#cc0','#0cc','#ccc'];
  game.bots.forEach((bot,i)=>{
    if(bot.finishTick!==null)return;
    ctx.fillStyle=colors[i%colors.length];
    const x=(bot.pos.c+0.5)*cellSize,y=(bot.pos.r+0.5)*cellSize;
    ctx.beginPath();ctx.arc(x,y,cellSize/8,0,Math.PI*2);ctx.fill();
  });
}

document.getElementById('reset').addEventListener('click',()=>initGame());
initGame();

})();
</script>
</body>
</html>
